public int[] withoutTen(int[] nums)
{
    int[] array = new int[nums.length];

    for (int i : nums)
    {
        for (int j : array)
        {
            if (i != 10)
            {
                array[j] = i;
                break;
            }
        }
    }

   return array;
}

